const positionDropdown = (triggerRef, dropdownRef) => {
  const trigger = triggerRef.current?.getBoundingClientRect();
  const dropdown = dropdownRef.current;
  if (!trigger || !dropdown) return;

  dropdown.style.top = `${trigger.bottom + window.scrollY}px`;
  dropdown.style.left = `${trigger.left + window.scrollX}px`;
};

